{
  "title": "Java Programming for Beginners: Data Structures Focus",
  "description": "This course is designed for beginners who want to learn Java programming with a specific focus on data structures, preparing them for opportunities in Japan's tech industry.",
  "modules": [
    {
      "id": "module1",
      "title": "Introduction to Java",
      "description": "Learn the basics of Java programming, including syntax, data types, and control structures. This module sets the foundation for understanding Java."
    },
    {
      "id": "module2",
      "title": "Object-Oriented Programming in Java",
      "description": "Explore the principles of object-oriented programming (OOP) in Java, including classes, objects, inheritance, and polymorphism, essential for building robust applications."
    },
    {
      "id": "module3",
      "title": "Understanding Data Structures",
      "description": "Dive into various data structures in Java such as arrays, linked lists, stacks, and queues. Learn how to implement and manipulate these structures effectively."
    },
    {
      "id": "module4",
      "title": "Advanced Data Structures and Algorithms",
      "description": "Expand your knowledge with advanced data structures like trees and graphs, and understand algorithms for searching and sorting, preparing you for real-world programming challenges."
    }
  ]
}
